const crypto = require('crypto');
const item = $input.item;
const headers = (item.json && item.json.headers) || {};
const sigHeader = headers['x-hub-signature-256'] || headers['X-Hub-Signature-256'] || '';
const secret = $env.WHATSAPP_APP_SECRET || '';
let rawBody = null;
if (item.binary && item.binary.data && item.binary.data.data) {
  rawBody = Buffer.from(item.binary.data.data, 'base64');
} else if (typeof item.json.body === 'string') {
  rawBody = Buffer.from(item.json.body, 'utf8');
}
if (rawBody === null) {
  return [{ json: { valid: false, reason: 'raw_body_unavailable', received_signature_prefix: sigHeader.slice(0, 24), raw_body_length: 0, body_parsed: null } }];
}
const computed = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
let valid = false;
const prefix = 'sha256=';
if (sigHeader.startsWith(prefix) && secret.length > 0) {
  const received = sigHeader.slice(prefix.length);
  if (received.length === computed.length) {
    try { valid = crypto.timingSafeEqual(Buffer.from(received, 'hex'), Buffer.from(computed, 'hex')); } catch (e) { valid = false; }
  }
}
let bodyParsed = null;
try { bodyParsed = JSON.parse(rawBody.toString('utf8')); } catch (e) { bodyParsed = item.json.body || null; }
return [{ json: { valid, body_parsed: bodyParsed, received_signature_prefix: sigHeader.slice(0, 24), raw_body_length: rawBody.length } }];

const body = $('Validate HMAC').item.json.body_parsed;
if (!body || !body.entry || !body.entry[0]) return [{ json: { valid: false, reason: 'no_entry' } }];
const change = body.entry[0].changes && body.entry[0].changes[0];
if (!change || !change.value) return [{ json: { valid: false, reason: 'no_change' } }];
const msg = change.value.messages && change.value.messages[0];
if (!msg) return [{ json: { valid: false, reason: 'no_message' } }];
const from = msg.from || '';
const cleaned = from.replace(/\s+/g, '').replace(/-/g, '');
const phoneE164 = cleaned.startsWith('+') ? cleaned : '+' + cleaned;
if (!phoneE164.startsWith('+233') || phoneE164.length !== 13) {
  return [{ json: { valid: false, reason: 'invalid_ghana_phone', raw_from: from } }];
}
return [{ json: {
  valid: true,
  phoneE164,
  waMessageId: msg.id,
  messageType: msg.type,
  messageBody: msg.type === 'text' ? (msg.text && msg.text.body) : '',
  mediaUrl: msg.type === 'audio' ? (msg.audio && msg.audio.id) : null,
  rawMessage: msg
} }];

const body = ($('Set Candidate Context').first()?.json?.messageBody || '').trim().toUpperCase();
let intent = 'OTHER';
if (['YES', 'YES PLEASE', 'I AGREE', 'AGREE', 'OK', 'OKAY', 'SURE', 'ACCEPT'].some(k => body === k || body.startsWith(k + ' '))) intent = 'YES';
else if (['NO', 'STOP', 'REFUSE', 'NOPE', 'DONT', "DON'T", 'NOT INTERESTED'].some(k => body === k || body.startsWith(k + ' '))) intent = 'NO';
else if (['DATA', 'DELETE', 'FORGET', 'ACCESS', 'REMOVE MY DATA', 'DELETE MY DATA'].some(k => body === k || body.startsWith(k))) intent = 'DPA';
return [{ json: { ...$input.item.json, consentIntent: intent } }];

const segs = $json.segments || [];
const avgLogprob = segs.length > 0 ? segs.reduce((s, sg) => s + (sg.avg_logprob || 0), 0) / segs.length : ($json.avg_logprob || -1);
const noSpeech = $json.no_speech_prob || 0;
const text = $json.text || '';
const compressionRatio = $json.compression_ratio || ($json.segments && $json.segments[0] ? $json.segments[0].compression_ratio : 2.0) || 2.0;
let quality = 'unavailable';
if (text && text.trim().length > 0) {
  if (avgLogprob >= -0.3 && noSpeech <= 0.5 && compressionRatio >= 1.5 && compressionRatio <= 3.5) quality = 'high';
  else quality = 'low';
}
return [{ json: { ...$input.item.json, transcript: text, transcriptQuality: quality, avgLogprob, noSpeech, compressionRatio } }];

let parsed = {};
try { parsed = JSON.parse($json.content || '{}'); } catch (e) { parsed = { intent: 'open_conversation', confidence: 0.5 }; }
const intent = parsed.intent || 'open_conversation';
const confidence = typeof parsed.confidence === 'number' ? parsed.confidence : 0.5;
const riskyLowConfidence = confidence < 0.7 && ['workflow_reply', 'dpa_request', 'distress'].includes(intent);
return [{ json: { ...$input.item.json, intent, confidence, riskyLowConfidence } }];
